sql:
SELECT value_root_1, distance_between_roots
FROM root_pairs
ORDER BY distance_between_roots DESC;

SELECT dataset_id, COUNT(pair_id) AS root_pair_count
FROM root_pairs
GROUP BY dataset_id;

